package tests;import base.BaseTestPlaywright;import com.microsoft.playwright.Page;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP06AgregarPlatoPlaywrightTest extends BaseTestPlaywright {    @Test    void cocineroAgregaNuevoPlato() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("cocinero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        page.locator("a:has-text('Añadir Plato')").click();        page.waitForTimeout(1000);        String nombrePlato = "Plato QA " + System.currentTimeMillis();        page.locator("input[name='name']").fill(nombrePlato);        page.locator("textarea[name='description']").fill("Creado por Playwright");        page.locator("input[name='price']").fill("25");        page.locator("button:has-text('Crear')").click();        page.waitForTimeout(2000);        assertTrue(                page.content().contains("Panel Cocinero"),                "Después de crear el plato no regresó al Panel Cocinero."        );        assertTrue(                page.content().contains("Añadir Plato"),                "No se visualiza el botón Añadir Plato después de crear el plato."        );        page.screenshot(                new Page.ScreenshotOptions()                        .setPath(Paths.get("evidencias/HP06-agregar-plato.png"))                        .setFullPage(true)        );    }}